INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00440', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲將其對乙之新臺幣100萬元債權讓與丙。下列敘述，何者錯誤？', '["乙若有提供債權之擔保於甲，則該擔保隨同移轉於丙", "若甲未曾通知乙債權之讓與，則雖丙已向乙為債權讓與之通知，若乙仍向甲為給付，依民法規 定，即發生清償之效力", "甲有將證明債權之文件，交付丙之義務", "受讓人將讓與人所立之讓與字據提示於債務人者，與通知有同一之效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00441', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '「當事人之一方對他方負金錢或其他代替物之給付義務而約定以之作為消費借貸之標的」之契 約，關於該契約性質，下列敘述，何者錯誤？', '["成立消費借貸契約", "為不要式契約", "為物權契約", "為要因契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00442', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲經乙銀行錄取為行員，報到前乙要求甲提供保證人，甲遂要求其好友丙為其保證。保證書中約 明，保證人丙於甲受僱於乙銀行期間虧空公款或其他違法違規行為造成乙銀行損害者，丙願意代 甲負賠償責任，丙並願拋棄保證人一切抗辯權。10年後，甲升任分行經理，年收入為新臺幣（下 同）5百萬元，然其隨即侵占公款1千萬元，並經判刑確定。下列敘述，何者正確？', '["稱人事保證者，謂當事人約定，一方於他方之受僱人將來因職務上之行為而應對他方為損害賠 償時，由其代負賠償責任之契約。甲侵占公款之行為，並非職務上之行為，故丙無須代負責任", "丙所訂立之人事保證契約，有效期間已經屆滿，丙無須負責", "人事保證未定期間者，保證人得隨時終止契約。但因丙並未終止契約，故仍應負賠償責任。但 該賠償金額，以5百萬元為上限", "丙所訂立之人事保證契約仍為有效，丙應代為賠償1千萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00443', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲以自己所有之A地為乙設定普通地上權，約定期限50年，地租為每年新臺幣100萬元，乙在 該地建築B大樓。下列關於該地上權之敘述，何者錯誤？', '["地上權人乙得於期間屆滿前，定1個月以上之期間，請求土地所有人甲按該建築物之時價為補償", "土地所有人甲得請求延長地上權之期間。於延長之期間，地上權人乙無須繳交地租", "地上權人乙得支付未到期之3年分地租後，拋棄其權利", "若B大樓因地震而全部震垮，地上權不因而消滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00444', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲、乙、丙、丁公同共有A地，甲為避免繳稅之困擾，希望拋棄其對於A地公同共有之權利，甲 於下列何種情形，始消滅其公同共有之權利？', '["甲通知乙、丙、丁拋棄之意思表示時", "甲陳報法院為拋棄之意思表示時", "甲依法到地政事務所完成登記時", "甲依法到戶政事務所完成登記時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00445', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '就物權之排他效力而言，下列何者為不得併存於同一標的物上之物權？', '["費用性擔保物權與融資性擔保物權", "區分地上權與普通地上權", "不動產役權與普通抵押權", "普通地上權與典權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00446', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '關於動產物權變動之交付要件，下列敘述，何者錯誤？', '["交付為事實行為之性質，故不得由代理方式為之，但得經由占有輔助人為之", "受讓人已占有動產者，於讓與合意時即生效力，此簡易交付之方式，於受讓人之占有為無權占 有時，則不適用", "占有改定之交付方式，不適用於動產質權之設定", "指示交付方式中，讓與人讓與受讓人之對第三人返還請求權，包括所有物之返還請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00447', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲有水泥一包，放置於家門口。乙為A屋所有人。乙未經甲之同意 ，以甲之該包水泥，整修A 屋之浴室。下列敘述，何者正確？', '["甲僅得請求乙返還一包水泥", "甲得請求乙將該包水泥原物返還", "甲因乙之行為與乙共有A屋，而不得請求返還水泥或水泥之價額", "甲得請求乙償還水泥一包之價額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00448', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲登記為A屋所有人。甲於A屋上設定普通抵押權於乙（第1次序抵押權），用以擔保對乙所負 之新臺幣（下同）180萬元借款債務；設定普通抵押權於丙（第2次序抵押權），用以擔保對丙所 負之120萬元借款債務；設定普通抵押權於丁（第3次序抵押權），用以擔保對丁所負之60萬元 借款債務。乙將其第1次序讓與丁，該讓與且經登記。法院拍賣A屋，拍得價金300萬元。下列 敘述，何者正確？', '["丁先分得45萬元", "丁先分得60萬元", "丁先分得120萬元", "丁先分得180萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00449', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於終止收養之敘述，何者正確？', '["夫妻共同收養子女後離婚者，夫妻之一方得於離婚後2年內，得逕向戶政機關申請單獨終止收 養登記", "養子女自收養關係終止時起，須向社會福利機關與法院辦理登記，始與本生父母間產生血親關係", "因收養關係終止而生活陷於困難者，得請求他方給與相當之金額，但其請求顯失公平者，得減 輕或免除之", "養子女有明顯浪費財產致侵吞養父母退休金之不當情事者，應由檢察官聲請法院宣告終止收養 關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
